package drift_detection

import (
	mock_opensearch "airwatch/uem/gumdrop-ingestion/internal/pkg/mocking/mock-opensearch"
	ff "airwatch/uem/gumdrop-ingestion/pkg/feature-flag"
	"airwatch/uem/gumdrop-ingestion/pkg/log"
	"airwatch/uem/gumdrop-ingestion/pkg/repository"
	"io"
	"strings"
	"testing"
	"time"

	"github.com/stretchr/testify/assert"
)

func Test_staleEntityDetector_remediateStaleEntities(t *testing.T) {
	type fields struct {
		client *mock_opensearch.MockOsClient
	}
	type args struct {
		logContext               *log.Context
		entityStalenessThreshold *string
		tenantUuid               *string
	}
	newClient := func() *mock_opensearch.MockOsClient {
		return &mock_opensearch.MockOsClient{
			SearchQueryResponse: createSearchResponse(),
		}
	}

	tests := []struct {
		name               string
		fields             fields
		featureFlag        ff.FeatureFlagChecker
		featureFlagEnabled bool
		CalledSearch       bool
		SearchCallCount    int
		CalledCreatePit    bool
		CalledDeletePit    bool
		args               args
	}{
		{
			name: "All entity remediation is called when FFs are on",
			fields: fields{
				client: newClient(),
			},
			CalledSearch:    true,
			SearchCallCount: 1, // only device is configured for auto remediation
		},
		{
			name:               "Device entity remediation is not called when FF is off",
			featureFlag:        ff.EnableDstRemediation,
			featureFlagEnabled: false,
			fields: fields{
				client: newClient(),
			},
			CalledSearch:    false,
			SearchCallCount: 0, // only for user
		},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			logContext := log.NewEmptyLogContext(0)

			if tt.featureFlag != nil {
				if tt.featureFlagEnabled {
					tt.featureFlag.Enable()
				} else {
					tt.featureFlag.Disable()
				}
			}

			s := NewStaleEntityDetector(
				testSchemaMapper,
				nil,
				tt.fields.client,
				nil,
				time.Second,
				2,
				time.Second,
				time.Millisecond*100,
			)

			assert.NotPanics(t, func() {
				s.DetectAndRemediate(
					logContext,
					nil,
				)
			})

			assert.Equal(t, tt.CalledSearch, tt.fields.client.CalledSearch)
			assert.Equal(t, tt.SearchCallCount, tt.fields.client.SearchCallCount)
		})
	}
}

func createSearchResponse() *repository.QueryResponse[io.ReadCloser] {
	var (
		searchResponse = `{
    "took": 22,
    "timed_out": false,
    "status": 200,
    "hits": {
        "hits": []
    }
}
`
		queryResponse = &repository.QueryResponse[io.ReadCloser]{
			StatusCode: 200,
			Response:   io.NopCloser(strings.NewReader(searchResponse)),
		}
	)

	return queryResponse
}
