		indexMissingPropertiesDetectorName,
		MissingPropertiesParams{},
		client,
		remediationRequestEmitter,
		scheduler,
		schemaMapper,
		schedulerInterval,
		searchBatchSize,
		remediationRequestInterval,
	)
}

func (p MissingPropertiesParams) ShouldProcess(remediationConfig *schemaMapping.RemediationConfig) bool {
	return remediationConfig != nil && len(remediationConfig.RequiredProperties) > 0
}

func (p MissingPropertiesParams) CreateQuery(
	logContext *log.Context,
	tenantUuid *string,
	indexKey string,
	indexMetadata *schemaMapping.IndexMetadata,
	remediationConfig *schemaMapping.RemediationConfig,
	searchBatchSize int,
) *repository.QueryDetailsItem[*repository.QueryRequest[repository.Params]] {
	queryBody := repository.NewMissingOrDefaultPropertiesQueryRequest[repository.Params](
		logContext,
		tenantUuid,
		remediationConfig.RequiredProperties,
		indexMetadata.DefaultValuesMap,
	)

	queryBody.
		WithSize(searchBatchSize).
		WithSort(map[string]string{"_id": "asc"}).
		WithSource(remediationConfig.RequiredProperties)

	return &repository.QueryDetailsItem[*repository.QueryRequest[repository.Params]]{
		Indices:    []string{indexKey},
		Body:       queryBody,
		LogContext: queryBody.LogContext,
	}
}
