package drift_detection

import (
	"context"
	"fmt"
	"net/url"
	"time"

	"airwatch/uem/gumdrop-ingestion/internal/pkg/emitter"
	schemaMapping "airwatch/uem/gumdrop-ingestion/internal/pkg/schema-mapping"
	"airwatch/uem/gumdrop-ingestion/pkg"
	"airwatch/uem/gumdrop-ingestion/pkg/env"
	errorHandling "airwatch/uem/gumdrop-ingestion/pkg/error-handling"
	ff "airwatch/uem/gumdrop-ingestion/pkg/feature-flag"
	"airwatch/uem/gumdrop-ingestion/pkg/log"
	"airwatch/uem/gumdrop-ingestion/pkg/repository"
	"airwatch/uem/gumdrop-ingestion/pkg/scheduler"
	"airwatch/uem/gumdrop-ingestion/pkg/telemetry"
	"airwatch/uem/gumdrop-ingestion/pkg/telemetry/group"
	"airwatch/uem/gumdrop-ingestion/pkg/telemetry/metric"
	"airwatch/uem/gumdrop-ingestion/pkg/telemetry/metrics"
	uemApiClient "airwatch/uem/gumdrop-ingestion/pkg/uem-api-client"

	"github.com/google/uuid"
	jsoniter "github.com/json-iterator/go"
	"github.com/pkg/errors"
)

const (
	tenantUuidPropertyName           = "tenant_uuid"
	remediationBatchCorrelationIdKey = "remediation_batch_correlation_id"
)

var serviceLocationEnvToApiUrlMap = make(map[string]string)

type DriftParams interface {
	ShouldProcess(remediationConfig *schemaMapping.RemediationConfig) bool
	CreateQuery(
		logContext *log.Context,
		tenantUuid *string,
		indexKey string,
		indexMetadata *schemaMapping.IndexMetadata,
		remediationConfig *schemaMapping.RemediationConfig,
		searchBatchSize int,
	) *repository.QueryDetailsItem[*repository.QueryRequest[repository.Params]]
}

type DriftDetector[T DriftParams] interface {
	Start(context context.Context, logContext *log.Context)
	Stop()
	Done() <-chan struct{}
	DetectAndRemediate(logContext *log.Context, tenantUuid *string)
}

type baseDriftDetector[T DriftParams] struct {
	driftDetectorType          string
	driftDetectorParams        T
	client                     repository.NoSqlRepository
	remediationRequestEmitter  emitter.RemediationRequestEmitter
	remediationRequestInterval time.Duration
	scheduler                  scheduler.Scheduler
	schemaMapper               schemaMapping.SchemaMapper
	done                       chan struct{}
	schedulerInterval          time.Duration
	schedulerIntervalFormatted string
	searchBatchSize            int
}

func newBaseDriftDetector[T DriftParams](
	driftDetectorType string,
	driftDetectorParams T,
	client repository.NoSqlRepository,
	remediationRequestEmitter emitter.RemediationRequestEmitter,
	scheduler scheduler.Scheduler,
	schemaMapper schemaMapping.SchemaMapper,
	schedulerInterval time.Duration,
	searchBatchSize int,
	remediationRequestInterval time.Duration,
) DriftDetector[T] {
	return &baseDriftDetector[T]{
		driftDetectorType:          driftDetectorType,
		driftDetectorParams:        driftDetectorParams,
		client:                     client,
		remediationRequestEmitter:  remediationRequestEmitter,
		scheduler:                  scheduler,
		schemaMapper:               schemaMapper,
		done:                       make(chan struct{}),
		schedulerInterval:          schedulerInterval,
		schedulerIntervalFormatted: repository.FormatDuration(schedulerInterval),
		searchBatchSize:            searchBatchSize,
		remediationRequestInterval: remediationRequestInterval,
	}
}

func (d *baseDriftDetector[T]) Start(context context.Context, logContext *log.Context) {
	const startingDriftDetectorMessage = "%s: drift_detector.DetectAndRemediate: starting scheduler for detecting drift."

	log.Infow(logContext, fmt.Sprintf(startingDriftDetectorMessage, d.driftDetectorType))

	d.scheduler.Start(
		context,
		func() { d.DetectAndRemediate(logContext, nil) },
		d.schedulerInterval,
	)
}

func (d *baseDriftDetector[T]) Stop() {
	d.scheduler.Stop()
	close(d.done)
}

func (d *baseDriftDetector[T]) Done() <-chan struct{} {
	return d.done
}

func (d *baseDriftDetector[T]) DetectAndRemediate(
	logContext *log.Context,
	tenantUuid *string,
) {
	const (
		functionName                         = "%s: drift_detector.DetectAndRemediate"
		startingDriftDetectorMessage         = "%s: drift_detector.DetectAndRemediate: Detecting and remediating documents."
		skipIndexRemediationFeatureDisabled  = "%s: drift_detector.DetectAndRemediate: skipping remediation attempt on %s because the feature flag %s is disabled"
		searchingForDocumentsToRemediate     = "%s: drift_detector.DetectAndRemediate: searching for documents in %s index to remediate"
		errorOccurredWhileRemediatingIndex   = "%s: drift_detector.DetectAndRemediate: Error occurred when remediating documents in %s index"
		completedScheduledRemediationMessage = "%s: drift_detector.DetectAndRemediate: completed scheduled remediation. Waiting for next schedule in %s."
	)

	defer errorHandling.Recover(logContext, nil)

	log.Infow(logContext, fmt.Sprintf(startingDriftDetectorMessage, d.driftDetectorType), log.TenantUuidKey, tenantUuid)

	for indexKey, remediationConfig := range d.schemaMapper.GetIndexRemediationConfigMap() {
		if remediationConfig == nil || !d.driftDetectorParams.ShouldProcess(remediationConfig) {
			continue
		}

		if remediationConfig.FeatureFlag != nil && !ff.IsEnabled(*remediationConfig.FeatureFlag, false) {
			log.Warnw(
				logContext,
				fmt.Sprintf(
					skipIndexRemediationFeatureDisabled,
					d.driftDetectorType,
					indexKey,
					*remediationConfig.FeatureFlag,
				),
			)

			continue
		}

		indexMetadata, _ := d.schemaMapper.GetIndexMetadataByIndexKey(indexKey)

		query := d.driftDetectorParams.CreateQuery(
			logContext,
			tenantUuid,
			indexKey,
			indexMetadata,
			remediationConfig,
			d.searchBatchSize,
		)

		log.Infow(
			logContext,
			fmt.Sprintf(searchingForDocumentsToRemediate, d.driftDetectorType, indexKey),
			log.TenantUuidKey,
			tenantUuid,
		)

		err := d.detectAndRemediateDrift(
			logContext,
			fmt.Sprintf(functionName, d.driftDetectorType),
			remediationConfig.EntitySchemaName,
			remediationConfig,
			tenantUuid,
			query,
		)

		if err != nil {
			log.Errorw(
				logContext,
				fmt.Sprintf(errorOccurredWhileRemediatingIndex, d.driftDetectorType, indexKey),
				log.ErrorKey,
				err,
				log.TenantUuidKey,
				tenantUuid,
				log.IndexName,
				indexKey,
				log.EntityNameKey,
				remediationConfig.EntitySchemaName,
				log.ErrorResponse,
				errorHandling.GetData[*repository.AnyResponse](err),
			)
		}
	}

	log.Infof(logContext, completedScheduledRemediationMessage, d.driftDetectorType, d.schedulerIntervalFormatted)
}

func (d *baseDriftDetector[T]) detectAndRemediateDrift(
	logContext *log.Context,
	callingFunctionName string,
	entityName string,
	remediationConfig *schemaMapping.RemediationConfig,
	tenantUuid *string,
	query *repository.QueryDetailsItem[*repository.QueryRequest[repository.Params]],
) error {
	const (
		errorOccurredWhenSearchingForDriftedEntities           = "%s: drift_detector.detectAndRemediateDrift: Error occurred during searching for drifted entity %s"
		noMoreDriftedEntitiesFoundToRemediate                  = "%s: drift_detector.detectAndRemediateDrift: End of page, or no more drifted %s entity found to remediate"
		foundDriftedEntitiesToRemediate                        = "%s: drift_detector.detectAndRemediateDrift: Found %d %s drifted entities to remediate"
		errorOccurredWhenRequestingFullStateForDriftedEntities = "%s: drift_detector.detectAndRemediateDrift: Error occurred when requesting full state for drifted entity %s"
		fetchingNextBatchOfDriftedEntities                     = "%s: drift_detector.detectAndRemediateDrift: More drifted %s entities are present, waiting %s before fetching next batch."
	)

	defer errorHandling.Recover(logContext, nil, log.EntityNameKey, entityName)

	// fetch a batch of drifted entities and remediate them before fetching
	// the next batch
	var (
		searchResponse  *repository.SearchQueryResponse[map[string]any]
		driftedEntities []*repository.Hit[map[string]any]
		err             error
	)

	for {
		remediationBatchCorrelationId := uuid.NewString()
		searchResponse, err = d.executeSearchQuery(logContext, query)
		if err != nil {
			return errors.Wrapf(err, errorOccurredWhenSearchingForDriftedEntities, callingFunctionName, entityName)
		}

		if searchResponse == nil || searchResponse.Hits == nil || len(searchResponse.Hits.Hits) == 0 {
			// nothing to remediate
			log.Infow(
				logContext,
				fmt.Sprintf(noMoreDriftedEntitiesFoundToRemediate, callingFunctionName, entityName),
				log.TenantUuidKey,
				tenantUuid,
				log.EntityNameKey,
				entityName,
				remediationBatchCorrelationIdKey,
				remediationBatchCorrelationId,
			)
			return nil
		}

		driftedEntities = searchResponse.Hits.Hits

		log.Infow(
			logContext,
			fmt.Sprintf(foundDriftedEntitiesToRemediate, callingFunctionName, len(driftedEntities), entityName),
			log.TenantUuidKey,
			tenantUuid,
			log.EntityNameKey,
			entityName,
			remediationBatchCorrelationIdKey,
			remediationBatchCorrelationId,
		)

		err := d.requestFullStateEventsForDriftedEntities(
			logContext,
			callingFunctionName,
			remediationBatchCorrelationId,
			remediationConfig,
			driftedEntities,
		)
		if err != nil {
			return errors.Wrapf(
				err,
				errorOccurredWhenRequestingFullStateForDriftedEntities,
				callingFunctionName,
				entityName,
			)
		}

		telemetry.Count(
			logContext,
			group.DriftDetection,
			metric.RemediatedEntitiesCount,
			int64(len(driftedEntities)),
			metrics.NewTag(telemetry.EntityNameTag, entityName),
		)

		searchAfter := driftedEntities[len(driftedEntities)-1].Sort
		if searchAfter == nil {
			break
		}

		// Add delay before making the next call
		query.Body.WithSearchAfter(searchAfter)

		log.Infow(
			logContext,
			fmt.Sprintf(
				fetchingNextBatchOfDriftedEntities,
				callingFunctionName,
				entityName,
				d.remediationRequestInterval,
			),
		)
		time.Sleep(d.remediationRequestInterval)
	}

	return nil
}

func (d *baseDriftDetector[T]) executeSearchQuery(
	logContext *log.Context,
	query *repository.QueryDetailsItem[*repository.QueryRequest[repository.Params]],
) (*repository.SearchQueryResponse[map[string]any], error) {
	const (
		functionName                              = "drift_detector.executeSearchQuery"
		errorOccurredWhenSearchingDriftedEntities = "drift_detector.executeSearchQuery: Error occurred during searching for drifted entities"
		failedToDecodeResponse                    = "drift_detector.executeSearchQuery: failed to decode search response"
	)

	res, err := d.client.Search(logContext, query)
	if err != nil {
		return nil, errors.Wrap(err, errorOccurredWhenSearchingDriftedEntities)
	}

	searchResponse := &repository.SearchQueryResponse[map[string]any]{}
	err = jsoniter.NewDecoder(res.Response).Decode(searchResponse)
	if err != nil {
		return nil, errors.Wrap(err, failedToDecodeResponse)
	}

	return searchResponse, nil
}

func (d *baseDriftDetector[T]) requestFullStateEventsForDriftedEntities(
	logContext *log.Context,
	callingFunctionName string,
	remediationBatchCorrelationId string,
	remediationConfig *schemaMapping.RemediationConfig,
	documents []*repository.Hit[map[string]any],
) error {
	const (
		remediationSourceUrlNotDefined         = "%s: drift_detector.requestFullStateEventsForDriftedEntities: remediation source %s is not defined."
		failedToConstructRemediationApiUrl     = "%s: drift_detector.requestFullStateEventsForDriftedEntities: failed to construct remediation API url. Base url: %s, API url: %s"
		initiatingRemediationRequestLogMessage = "%s: drift_detector.requestFullStateEventsForDriftedEntities: initiating remediation request for entities."
		noEntityKeyPresentForDocLogMessage     = "%s: drift_detector.requestFullStateEventsForDriftedEntities: the drifted document for %s entity doesn't contain entity key properties"
		noFullStateRequestsCreatedLogMessage   = "%s: drift_detector.requestFullStateEventsForDriftedEntities: there are %d documents, but no full state requests were created."
		failedToEmitFullStateRequestLogMessage = "%s: drift_detector.requestFullStateEventsForDriftedEntities: Full state request failed."
		remediationRequestsKey                 = "remediation_requests"
	)

	var (
		tenantFullStateRequest = make(map[string]*uemApiClient.FullStateApiRequestModel)
		fullStateRequests      = make([]*uemApiClient.FullStateApiRequestModel, 0, 1)
		tenantUuid             string
		entityUniqueKeys       map[string]string
		apiUrl                 string
		err                    error
		ok                     bool
	)

	// figure out the source service url
	if apiUrl, ok = serviceLocationEnvToApiUrlMap[remediationConfig.ServiceUrlLookupEnv]; !ok {
		basePath := env.GetValue(logContext, remediationConfig.ServiceUrlLookupEnv)
		apiUrl, err = url.JoinPath(
			basePath,
			remediationConfig.ApiUrl,
		)
		if err != nil {
			log.Errorw(
				logContext,
				fmt.Sprintf(
					failedToConstructRemediationApiUrl,
					callingFunctionName,
					basePath,
					remediationConfig.ApiUrl,
				),
				log.ErrorKey,
				err,
			)

			return errors.Wrapf(
				err,
				remediationSourceUrlNotDefined,
				callingFunctionName,
				remediationConfig.ServiceUrlLookupEnv,
			)
		}

		serviceLocationEnvToApiUrlMap[remediationConfig.ServiceUrlLookupEnv] = apiUrl
	}

	for _, document := range documents {
		if document.Source == nil {
			continue
		}

		tenantUuid, entityUniqueKeys = extractEntityKeyProperties(
			remediationConfig.KeyProperties,
			document.Source,
		)

		if tenantUuid == "" || len(entityUniqueKeys) == 0 {
			log.Warnw(
				logContext,
				fmt.Sprintf(
					noEntityKeyPresentForDocLogMessage,
					callingFunctionName,
					remediationConfig.EntitySchemaName,
				),
				"drifted_doc",
				document,
				remediationBatchCorrelationIdKey,
				remediationBatchCorrelationId,
			)
			continue
		}

		var fullStateRequestModel *uemApiClient.FullStateApiRequestModel

		if fullStateRequestModel, ok = tenantFullStateRequest[tenantUuid]; !ok {
			fullStateRequestModel = &uemApiClient.FullStateApiRequestModel{
				CorrelationId:               remediationBatchCorrelationId,
				SourceEndpointTagMetricName: remediationConfig.ServiceUrlLookupEnv,
				ApiUrl:                      apiUrl,
				TokenServiceClientId:        env.GetValue(logContext, remediationConfig.TokenServiceClientIdLookupEnv),
				TokenServiceClientSecret: env.GetValue(
					logContext,
					remediationConfig.TokenServiceClientSecretLookupEnv,
				),
				ClientId:   pkg.ClientIdHeaderExpectedValue,
				TenantUuid: tenantUuid,
				Entities:   make([]*uemApiClient.Entity, 0, len(documents)),
			}
			tenantFullStateRequest[tenantUuid] = fullStateRequestModel
			fullStateRequests = append(fullStateRequests, fullStateRequestModel)
		}

		fullStateRequestModel.Entities = append(fullStateRequestModel.Entities, &uemApiClient.Entity{
			SchemaName: remediationConfig.EntitySchemaName,
			TenantUuid: &tenantUuid,
			UniqueKeys: entityUniqueKeys,
		})
	}

	if len(fullStateRequests) == 0 {
		log.Warnw(
			logContext,
			fmt.Sprintf(noFullStateRequestsCreatedLogMessage, callingFunctionName, len(documents)),
			"drifted_docs",
			documents,
			remediationBatchCorrelationIdKey,
			remediationBatchCorrelationId,
		)

		return nil
	}

	log.Infow(
		logContext,
		fmt.Sprintf(initiatingRemediationRequestLogMessage, callingFunctionName),
		remediationRequestsKey,
		fullStateRequests,
		remediationBatchCorrelationIdKey,
		remediationBatchCorrelationId,
	)

	_, err = d.remediationRequestEmitter.RequestFullStateEvents(logContext, fullStateRequests)
	if err != nil {
		return errors.Wrapf(err, failedToEmitFullStateRequestLogMessage, callingFunctionName)
	}

	return nil
}

// extractEntityKeyProperties extracts the tenant UUID and key properties from the given document.
//
// Parameters:
//   - indexEntityKeyPropertiesMap: []*schemaMapping.SourceTargetFieldMap - Mapping of source to target fields for the index entity.
//   - document: map[string]any - The document from which to extract the properties.
//
// Returns:
//   - string - The tenant UUID extracted from the document.
//   - map[string]string - A map of target field names to their corresponding values extracted from the document.
func extractEntityKeyProperties(
	indexEntityKeyPropertiesMap []*schemaMapping.SourceTargetFieldMap,
	document map[string]any,
) (string, map[string]string) {
	tenantUuid, _ := document[tenantUuidPropertyName].(string)
	keyPropertyMap := make(map[string]string, len(indexEntityKeyPropertiesMap))

	for _, property := range indexEntityKeyPropertiesMap {
		if value, ok := document[property.SourceFieldName].(string); ok {
			keyPropertyMap[property.TargetFieldName] = value
		}
	}

	return tenantUuid, keyPropertyMap
}
